    org_smtpConfig:      { de: 'SMTP-Konfiguration',        en: 'SMTP Configuration',         fr: 'Configuration SMTP',        nl: 'SMTP-configuratie' , tr: 'SMTP Yapılandırması' },
    org_securityNotice:  { de: 'Sicherheitshinweis',        en: 'Security notice',            fr: 'Avis de sécurité',          nl: 'Beveiligingsmelding' , tr: 'Güvenlik uyarısı' },
    org_smtpSecurityNotice:{ de: 'Das SMTP-Passwort wird in <code>org-settings.json</code> gespeichert (Klartext). Für höhere Sicherheit verwenden Sie Umgebungsvariablen (<code>SMTP_HOST</code> usw.) in <code>.env</code> — diese haben immer Vorrang.', en: 'The SMTP password is stored in <code>org-settings.json</code> (plaintext). For higher security, use environment variables (<code>SMTP_HOST</code> etc.) in <code>.env</code> — these always take precedence.', fr: 'Le mot de passe SMTP est stocké dans <code>org-settings.json</code> (texte clair). Pour plus de sécurité, utilisez des variables d’environnement (<code>SMTP_HOST</code>, etc.) dans <code>.env</code> — elles sont toujours prioritaires.', nl: 'Het SMTP-wachtwoord wordt opgeslagen in <code>org-settings.json</code> (platte tekst). Gebruik voor meer veiligheid omgevingsvariabelen (<code>SMTP_HOST</code>, enz.) in <code>.env</code> — die hebben altijd voorrang.' , tr: 'SMTP şifresi <code>org-settings.json</code> dosyasında (düz metin) saklanır. Daha yüksek güvenlik için <code>.env</code> içinde ortam değişkenlerini (<code>SMTP_HOST</code> vb.) kullanın — bunlar her zaman önceliklidir.' },
    org_smtpEnvOverride: { de: 'SMTP ist über <code>.env</code>-Variablen konfiguriert — UI-Einstellungen werden ignoriert.', en: 'SMTP is configured via <code>.env</code> variables — UI settings are ignored.', fr: 'SMTP est configuré via des variables <code>.env</code> — les paramètres de l’interface sont ignorés.', nl: 'SMTP is geconfigureerd via <code>.env</code>-variabelen — UI-instellingen worden genegeerd.' , tr: 'SMTP, <code>.env</code> değişkenleri üzerinden yapılandırılmış — arayüz ayarları dikkate alınmıyor.' },
