    org_testMailDesc:    { de: 'Die Testmail wird an die CISO-E-Mail ({email}) gesendet. Bitte zuerst unter Verantwortlichkeiten eine CISO-E-Mail eintragen.', en: 'Test mail will be sent to the CISO e-mail ({email}). Please enter a CISO e-mail under Responsibilities first.', fr: 'L’e-mail de test sera envoyé à l’e-mail du RSSI ({email}). Veuillez d’abord saisir un e-mail RSSI dans Responsabilités.', nl: 'De testmail wordt verzonden naar de CISO-e-mail ({email}). Voer eerst een CISO-e-mail in onder Verantwoordelijkheden.' , tr: 'Test e-postası CISO e-posta adresine ({email}) gönderilecektir. Lütfen önce Sorumluluklar bölümünde bir CISO e-postası girin.' },
    org_menuOrder:       { de: 'Menüreihenfolge',           en: 'Menu Order',                 fr: 'Ordre du menu',             nl: 'Menuvolgorde' , tr: 'Menü Sırası' },
    org_menuOrderDesc:   { de: 'Einträge mit <i class="ph ph-dots-six-vertical"></i> ziehen oder ↑/↓ verwenden, um die Sidebar-Reihenfolge anzupassen. Dashboard, Admin und Einstellungen werden immer angezeigt.', en: 'Drag entries with <i class="ph ph-dots-six-vertical"></i> or use ↑/↓ to adjust the sidebar order. Dashboard, Admin and Settings are always shown.', fr: 'Faites glisser les entrées avec <i class="ph ph-dots-six-vertical"></i> ou utilisez ↑/↓ pour ajuster l’ordre de la barre latérale. Tableau de bord, Admin et Paramètres sont toujours affichés.', nl: 'Sleep items met <i class="ph ph-dots-six-vertical"></i> of gebruik ↑/↓ om de zijbalkvolgorde aan te passen. Dashboard, Beheer en Instellingen worden altijd getoond.' , tr: 'Kenar çubuğu sırasını ayarlamak için girdileri <i class="ph ph-dots-six-vertical"></i> ile sürükleyin veya ↑/↓ kullanın. Panel, Yönetim ve Ayarlar her zaman gösterilir.' },
