    risk_openMeasures:   { de: 'Offene Maßnahmen',          en: 'Open Measures',              fr: 'Mesures ouvertes',          nl: 'Openstaande maatregelen' , tr: 'Açık Önlemler' },
    cvss_descCritical:   { de: 'Kritisch: Schwachstelle ermöglicht vollständige Systemkompromittierung, oft ohne Authentifizierung und Nutzerinteraktion (z.B. Remote Code Execution).', en: 'Critical: vulnerability can allow full system compromise, often without authentication or user interaction (for example remote code execution).', fr: 'Critique : la vulnérabilité peut permettre une compromission complète du système, souvent sans authentification ni interaction utilisateur.', nl: 'Kritiek: kwetsbaarheid kan volledige systeemcompromittering mogelijk maken, vaak zonder authenticatie of gebruikersinteractie.' , tr: 'Kritik: zafiyet, çoğunlukla kimlik doğrulama veya kullanıcı etkileşimi olmadan tam sistem ele geçirilmesine izin verebilir (örneğin uzaktan kod çalıştırma).' },
    cvss_descHigh:       { de: 'Hoch: Erheblicher Schaden möglich. Angreifer können wichtige Ressourcen kontrollieren oder vertrauliche Daten auslesen.', en: 'High: significant damage is possible. Attackers may control important resources or read confidential data.', fr: 'Élevé : des dommages importants sont possibles. Les attaquants peuvent contrôler des ressources importantes ou lire des données confidentielles.', nl: 'Hoog: aanzienlijke schade is mogelijk. Aanvallers kunnen belangrijke bronnen controleren of vertrouwelijke gegevens lezen.' , tr: 'Yüksek: önemli hasar mümkündür. Saldırganlar önemli kaynakları kontrol edebilir veya gizli verileri okuyabilir.' },
    cvss_descMedium:     { de: 'Mittel: Eingeschränkter Schaden oder Ausnutzung erfordert bestimmte Vorbedingungen (z.B. Netzwerkzugang, Benutzerinteraktion).', en: 'Medium: limited damage, or exploitation requires specific preconditions such as network access or user interaction.', fr: 'Moyen : dommages limités ou exploitation nécessitant des conditions préalables, comme un accès réseau ou une interaction utilisateur.', nl: 'Middel: beperkte schade, of exploitatie vereist specifieke voorwaarden zoals netwerktoegang of gebruikersinteractie.' , tr: 'Orta: sınırlı hasar veya istismar için ağ erişimi ya da kullanıcı etkileşimi gibi belirli ön koşullar gerekir.' },
    cvss_descLow:        { de: 'Niedrig: Minimaler Schaden, schwer ausnutzbar oder starke einschränkende Faktoren vorhanden.', en: 'Low: minimal damage, difficult exploitation, or strong limiting factors.', fr: 'Faible : dommages minimes, exploitation difficile ou facteurs fortement limitants.', nl: 'Laag: minimale schade, moeilijk uit te buiten of sterke beperkende factoren.' , tr: 'Düşük: minimal hasar, zor istismar veya güçlü sınırlayıcı faktörler.' },
    cvss_descNone:       { de: 'Kein Risiko: Keine Auswirkung auf Vertraulichkeit, Integrität oder Verfügbarkeit.', en: 'No risk: no impact on confidentiality, integrity, or availability.', fr: 'Aucun risque : aucun impact sur la confidentialité, l’intégrité ou la disponibilité.', nl: 'Geen risico: geen impact op vertrouwelijkheid, integriteit of beschikbaarheid.' , tr: 'Risk yok: gizlilik, bütünlük veya erişilebilirlik üzerinde etkisi yok.' },
    cvss_sourceNote:     { de: 'Einstufung nach CVSS v3.1', en: 'Classification according to CVSS v3.1', fr: 'Classification selon CVSS v3.1', nl: 'Classificatie volgens CVSS v3.1' , tr: 'CVSS v3.1\'e göre sınıflandırma' },

